/**
 * Returns locale-specific hero image, falling back to home hero.
 * Supported locales: 'en', 'es', 'nl', 'de'
 */
export function getHeroImage(images: any, locale: string): string {
  if (!images?.hero) return ''
  const localeKey = `localized${locale.charAt(0).toUpperCase() + locale.slice(1)}`
  if (locale !== 'es' && images.hero[localeKey]?.src) {
    return images.hero[localeKey].src
  }
  // Fallback to home hero for ES (default) or if locale-specific not found
  return images.hero?.home?.src || ''
}"}

